final:
module top_module(
    input D,
    input S,
    input R,
    input CLK,
    output Q
);reg DFF_Q_int;

    always @(posedge CLK) begin
        if (S) begin
            DFF_Q_int <= 1;
        end else if (R) begin
            DFF_Q_int <= 0;
        end else begin
            DFF_Q_int <= D;
        end
    end

    assign Q = DFF_Q_int;

endmodule
